class Solution:
    def PredictTheWinner(self, nums: List[int]) -> bool:
        n = len(nums)
        dp = [[0]*n for _ in range(n)]
        for i in range(n): dp[i][i] = nums[i]
        for ln in range(2, n+1):
            for l in range(n-ln+1):
                r = l+ln-1
                dp[l][r] = max(nums[l]-dp[l+1][r], nums[r]-dp[l][r-1])
        return dp[0][n-1] >= 0

