bool predictTheWinner(int* nums, int n) {
    int dp[20][20]={0};
    for(int i=0;i<n;i++) dp[i][i]=nums[i];
    for(int len=2;len<=n;len++)
        for(int l=0;l+len-1<n;l++){
            int r=l+len-1;
            int a=nums[l]-dp[l+1][r], b=nums[r]-dp[l][r-1];
            dp[l][r]=a>b?a:b;
        }
    return dp[0][n-1]>=0;
}
